import{o as i,c as n,j as s,n as t,e as r,ae as c,p as d}from"./chunks/framework.BSk3HXt1.js";const o={class:"language-toggle-wrapper"},p={class:"language-toggle-bar"},h={class:"bilingual-title"},u={key:0,class:"zh-text"},g={key:1,class:"en-text"},w=JSON.parse('{"title":"尋味全球：盤點世界上最美味的鬆餅與薄餅 | World’s Most Delicious Pancakes","description":"從優雅細緻的法式薄餅，到厚實蓬鬆的美式鬆餅，再到外酥內Q的中式蔥油餅。本文帶您橫跨各大洲，探索全球最受歡迎的鬆餅代表！","frontmatter":{"title":"尋味全球：盤點世界上最美味的鬆餅與薄餅 | World’s Most Delicious Pancakes","description":"從優雅細緻的法式薄餅，到厚實蓬鬆的美式鬆餅，再到外酥內Q的中式蔥油餅。本文帶您橫跨各大洲，探索全球最受歡迎的鬆餅代表！"},"headers":[],"relativePath":"news/worlds-most-delicious-pancakes.md","filePath":"news/worlds-most-delicious-pancakes.md"}'),v={name:"news/worlds-most-delicious-pancakes.md"},f=Object.assign(v,{setup(b){const a=d("bilingual");return(m,e)=>(i(),n("div",null,[s("div",o,[s("div",p,[s("button",{class:t(["language-toggle-btn",{active:a.value==="bilingual"}]),onClick:e[0]||(e[0]=l=>a.value="bilingual")},"中英雙語",2),s("button",{class:t(["language-toggle-btn",{active:a.value==="zh"}]),onClick:e[1]||(e[1]=l=>a.value="zh")},"純中文",2),s("button",{class:t(["language-toggle-btn",{active:a.value==="en"}]),onClick:e[2]||(e[2]=l=>a.value="en")},"純英文",2)])]),s("div",{class:t(["bilingual-article","mode-"+a.value])},[s("h1",h,[a.value!=="en"?(i(),n("span",u,"尋味全球：盤點世界上最美味的鬆餅與薄餅")):r("",!0),a.value!=="zh"?(i(),n("span",g,"World’s Most Delicious Pancakes across Every Culture")):r("",!0)]),e[3]||(e[3]=c('<div style="text-align:center;margin:24px 0 32px 0;"><img src="/ai-news/worlds-most-delicious-pancakes/hero_pancakes.webp" alt="Delicious Pancakes Stack" style="border-radius:16px;max-width:100%;box-shadow:0 8px 32px rgba(0,0,0,0.15);border:1px solid rgba(255,255,255,0.08);"></div><div class="bilingual-paragraph"><p class="zh-text">鬆餅與薄餅（Pancakes）種類繁多，由各式各樣的食材製成。數千年來，無論是何種文化與信仰，它們都裝點著世界各地的餐桌。</p><p class="en-text">Pancakes — in all sorts of forms, made from all sorts of ingredients — have graced tables around the world for millennia, across every culture and creed.</p></div><div class="bilingual-paragraph"><p class="zh-text">它們可以是甜的，也可以是鹹的。有些薄餅是用鷹嘴豆粉等特殊麵粉製成；有些則是由馬鈴薯或大麻蛋白製成。在歐洲、非洲、亞洲及更遠的地方，人們以各種形式享用著它們。在甜味陣營中，鬆餅通常會放上水果或淋上楓糖漿；而在鹹味陣營中，酸奶油與各種鹹味薄餅則是絕配。</p><p class="en-text">They can be sweet or savory. Some pancakes are made with special kinds of flour such as chickpea flour. Others are made of potatoes or hemp protein. In their various forms, they are enjoyed across Europe, Africa, Asia and beyond. On the sweet end of the spectrum, pancakes are often topped with fruit or slathered with syrup, while sour cream pairs nicely with savory versions.</p></div><div class="bilingual-paragraph"><p class="zh-text">由於麵糊中通常融合了奶油和雞蛋等豐富食材，在歷史上，鬆餅常在齋戒期開始前食用。此外，它們也經常作為週末的犒賞或節日的經典佳餚，為人們帶來滿滿的幸福感。</p><p class="en-text">Since the batter often combines butter and eggs, which are rich foods, pancakes have historically been served before occasions of fasting. They are also frequently enjoyed as a weekend treat or holiday dish.</p></div><div class="bilingual-paragraph"><p class="zh-text">雖然很難為「鬆餅/薄餅」下一個絕對權威且無爭議的定義，但以下是我們為您精選的世界各地最棒、最美味的代表作。</p><p class="en-text">Although finding a definitive pancake definition is difficult, and doubtless contentious, here are some of the very best pancakes around the world.</p></div><hr><h2 class="bilingual-header"><span class="zh-text">🥞 全球四大超人氣鬆餅與薄餅</span><span class="en-text">Four Masterpieces from the Pancake Hall of Fame</span></h2><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">🇫🇷 法式薄餅 (French Crêpes)</h3><span class="dish-card-badge">Brittany, France</span></div><div class="bilingual-paragraph"><div style="text-align:center;margin:16px 0;"><img src="/ai-news/worlds-most-delicious-pancakes/french_crepes.webp" alt="法式薄餅 (French Crêpes)" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><p class="zh-text">在「鬆餅名人堂」中，法式薄餅（Crêpes）絕對佔有一席之地。這種極薄的煎餅起源於法國西北部的布列塔尼（Brittany），歷史可追溯至 13 世紀。如今它已演變成風靡全球的經典甜點，裹上榛果可可醬或簡單撒上糖粉，皆令人回味無窮。</p><p class="en-text">French crêpes would be hard to beat in the Pancake Hall of Fame. These ultra-thin pancakes originated in Brittany in northwest France, way back in the 13th century, but have since become beloved the world over.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">🇺🇸 美式酪乳鬆餅 (Buttermilk Pancakes)</h3><span class="dish-card-badge">United States</span></div><div class="bilingual-paragraph"><div style="text-align:center;margin:16px 0;"><img src="/ai-news/worlds-most-delicious-pancakes/american_pancakes.webp" alt="美式酪乳鬆餅 (Buttermilk Pancakes)" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><p class="zh-text">口感厚實而蓬鬆，淋上滿滿的楓糖漿，再配上帶有鹹香、酥脆的培根——極少有鬆餅能與經典的美式鬆餅塔相媲美。這種甜鹹交織的奢華享受，是美式早餐最具代表性的圖騰。</p><p class="en-text">Thick and fluffy, drenched in maple syrup and often served with the contrast of salty, crispy bacon, few pancakes rival the decadence of a classic stack of American pancakes.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">🇯🇵 日式舒芙蕾厚鬆餅 (Fluffy Pancakes)</h3><span class="dish-card-badge">Japan</span></div><div class="bilingual-paragraph"><div style="text-align:center;margin:16px 0;"><img src="/ai-news/worlds-most-delicious-pancakes/japanese_pancakes.webp" alt="日式舒芙蕾厚鬆餅 (Fluffy Pancakes)" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><p class="zh-text">近年来在日本和全球掀起狂潮的舒芙蕾厚鬆餅，以極致的空氣感、高聳挺拔的外觀以及令人驚嘆的「Duang Duang」抖動感著稱。它們採用打發的蛋白霜小火慢煎而成，質地輕盈宛如雲朵，入口即化。</p><p class="en-text">These towering, airy, soufflé-style creations wobble with delight and are celebrated for their incredible, cotton-candy texture. Made by folding whipped egg whites into the batter and cooking them slowly, they melt in your mouth like a cloud.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">🇨🇳 中式傳統蔥油餅 (Scallion Pancakes)</h3><span class="dish-card-badge">China</span></div><div class="bilingual-paragraph"><div style="text-align:center;margin:16px 0;"><img src="/ai-news/worlds-most-delicious-pancakes/scallion_pancakes.webp" alt="中式傳統蔥油餅 (Scallion Pancakes)" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><p class="zh-text">與大多數西式甜麵糊不同，這種香氣四溢、外皮金黃酥脆的蔥油餅實際上是由麵團製成的。在層層擀平的麵皮中揉入青蔥與椒鹽，煎熟後形成多層次、外酥內Q且富有嚼勁的絕妙口感，是中式鹹點的經典之作。</p><p class="en-text">Unlike most sweet-batter pancakes, these fragrant, crispy scallion pancakes are actually made from laminated dough, rather than batter, bringing about an incredibly crispy, flaky and chewy savory texture.</p></div></div><div class="original-source-wrapper"><div class="source-label"><span class="zh-text">🌐 閱讀英文原文：</span><span class="en-text">🌐 Read Original Article:</span></div><a href="https://www.cnn.com/travel/article/worlds-most-delicious-pancakes/index.html" target="_blank" rel="noopener noreferrer" class="source-link-btn"> CNN Travel <span style="font-size:0.8rem;">↗</span></a></div>',12))],2)]))}});export{w as __pageData,f as default};
